// ===============================
// FINAL DASHBOARD.JS
// Supports:
// - Add Travel
// - Add Ticket
// - File Upload (PDF + JPG/PNG)
// - Chart.js Bar + Line Graph
// - Monthly PDF Report Download
// - Dashboard Summary, History
// ===============================

import React, { useEffect, useState } from "react";
import {
  getDashboard,
  getHistory,
  getGraphData,
  addTravel,
  addTicket,
  uploadBill,
} from "./api/auth";   // ✅ FIXED PATH


import { Bar, Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend
);

export default function Dashboard({ employee, onLogout }) {
  const empId = employee?.empId;

  // UI tabs
  const [tab, setTab] = useState("dashboard");

  // Data states
  const [summary, setSummary] = useState(null);
  const [history, setHistory] = useState({ travel: [], ticket: [] });
  const [graph, setGraph] = useState([]);
  const [loading, setLoading] = useState(false);

  // Travel Form
  const [travelForm, setTravelForm] = useState({
    travel_date: "",
    location_from: "",
    location_to: "",
    purpose: "",
    mode_of_travel: "",
    amount: "",
  });

  // Ticket Form
  const [ticketForm, setTicketForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });

  // Bill Upload
  const [billForm, setBillForm] = useState({
    file: null,
    month_year: "",
  });

  useEffect(() => {
    if (empId) loadAll();
  }, [empId]);

  const loadAll = async () => {
    setLoading(true);
    try {
      const s = await getDashboard(empId);
      if (s.data.success) setSummary(s.data.dashboard);

      const h = await getHistory(empId);
      if (h.data.success) setHistory(h.data.history);

      const g = await getGraphData(empId);
      if (g.data.success) setGraph(g.data.graph);
    } catch (err) {
      console.log(err);
      alert("Error loading dashboard");
    }
    setLoading(false);
  };

  // --------------------------
  // ADD TRAVEL
  // --------------------------
  const submitTravel = async (e) => {
    e.preventDefault();
    try {
      const res = await addTravel({
        empId,
        ...travelForm,
        amount: parseFloat(travelForm.amount),
      });

      if (res.data.success) {
        alert("Travel Expense Added");
        setTravelForm({
          travel_date: "",
          location_from: "",
          location_to: "",
          purpose: "",
          mode_of_travel: "",
          amount: "",
        });
        loadAll();
        setTab("history");
      }
    } catch {
      alert("Travel upload failed");
    }
  };

  // --------------------------
  // ADD TICKET
  // --------------------------
  const submitTicket = async (e) => {
    e.preventDefault();
    try {
      const res = await addTicket({
        empId,
        ...ticketForm,
        amount: parseFloat(ticketForm.amount),
      });

      if (res.data.success) {
        alert("Ticket Added");
        setTicketForm({
          ticket_date: "",
          purpose: "",
          assigned_to: "",
          amount: "",
        });
        loadAll();
        setTab("history");
      }
    } catch {
      alert("Ticket upload failed");
    }
  };

  // --------------------------
  // UPLOAD BILL (PDF + Image)
// --------------------------
  const submitBill = async (e) => {
    e.preventDefault();

    if (!billForm.file) {
      alert("Upload a file");
      return;
    }

    // 1. Upload file
    const formData = new FormData();
    formData.append("bill", billForm.file);
    formData.append("empId", empId);

    const uploadRes = await fetch("https://prasa-app-yde3.onrender.com/api/upload/billfile"
, {
      method: "POST",
      body: formData,
    });

    const uploadData = await uploadRes.json();

    if (!uploadData.success) {
      alert("File upload failed");
      return;
    }

    // 2. Save metadata
    const metaRes = await uploadBill({
      empId,
      file_name: billForm.file.name,
      file_path: uploadData.filePath,
      month_year: billForm.month_year,
    });

    if (metaRes.data.success) {
      alert("Bill Uploaded Successfully");
      setBillForm({ file: null, month_year: "" });
      loadAll();
      setTab("history");
    }
  };

  // --------------------------
  // GENERATE PDF REPORT
  // --------------------------
  const generatePDF = async () => {
    const body = {
      empId,
      report_month: prompt("Enter month (YYYY-MM)", "2025-01"),
      total_travel: summary.totalTravel,
      total_ticket: summary.totalTicket,
    };

    const res = await fetch("https://prasa-app-yde3.onrender.com/api/generate-pdf"
, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });

    const data = await res.json();

    if (data.success) {
      window.open(`http://localhost:9000${data.file}`, "_blank");
    }
  };

  // --------------------------
  // UI START
  // --------------------------
  return (
    <div style={{ padding: 20 }}>
      <header>
        <h2>Welcome, {employee.empName}</h2>
        <button onClick={onLogout}>Logout</button>
      </header>

      {/* Nav Buttons */}
      <div style={{ marginTop: 20, display: "flex", gap: 10 }}>
        <button onClick={() => setTab("dashboard")}>Dashboard</button>
        <button onClick={() => setTab("addTravel")}>Add Travel</button>
        <button onClick={() => setTab("addTicket")}>Add Ticket</button>
        <button onClick={() => setTab("tools")}>Tools</button>
        <button onClick={() => setTab("history")}>History</button>
        <button onClick={() => setTab("graph")}>Graph</button>
      </div>

      <hr />

      {/* ---------------- DASHBOARD SUMMARY ---------------- */}
      {tab === "dashboard" && summary && (
        <div>
          <h3>Summary</h3>
          <p>Total Travel: ₹{summary.totalTravel}</p>
          <p>Total Ticket: ₹{summary.totalTicket}</p>
          <p>Total Bills: {summary.totalBills}</p>

          <button onClick={generatePDF}>Download Monthly PDF Report</button>
        </div>
      )}

      {/* ---------------- ADD TRAVEL ---------------- */}
      {tab === "addTravel" && (
        <form onSubmit={submitTravel}>
          <h3>Add Travel</h3>

          <input
            type="date"
            value={travelForm.travel_date}
            onChange={(e) => setTravelForm({ ...travelForm, travel_date: e.target.value })}
          />

          <input
            placeholder="From"
            value={travelForm.location_from}
            onChange={(e) => setTravelForm({ ...travelForm, location_from: e.target.value })}
          />

          <input
            placeholder="To"
            value={travelForm.location_to}
            onChange={(e) => setTravelForm({ ...travelForm, location_to: e.target.value })}
          />

          <input
            placeholder="Purpose"
            value={travelForm.purpose}
            onChange={(e) => setTravelForm({ ...travelForm, purpose: e.target.value })}
          />

          <input
            placeholder="Mode of Travel"
            value={travelForm.mode_of_travel}
            onChange={(e) => setTravelForm({ ...travelForm, mode_of_travel: e.target.value })}
          />

          <input
            placeholder="Amount"
            type="number"
            value={travelForm.amount}
            onChange={(e) => setTravelForm({ ...travelForm, amount: e.target.value })}
          />

          <button type="submit">Add Travel</button>
        </form>
      )}

      {/* ---------------- ADD TICKET ---------------- */}
      {tab === "addTicket" && (
        <form onSubmit={submitTicket}>
          <h3>Add Ticket</h3>

          <input
            type="date"
            value={ticketForm.ticket_date}
            onChange={(e) => setTicketForm({ ...ticketForm, ticket_date: e.target.value })}
          />

          <input
            placeholder="Purpose"
            value={ticketForm.purpose}
            onChange={(e) => setTicketForm({ ...ticketForm, purpose: e.target.value })}
          />

          <input
            placeholder="Assigned To"
            value={ticketForm.assigned_to}
            onChange={(e) => setTicketForm({ ...ticketForm, assigned_to: e.target.value })}
          />

          <input
            placeholder="Amount"
            type="number"
            value={ticketForm.amount}
            onChange={(e) => setTicketForm({ ...ticketForm, amount: e.target.value })}
          />

          <button type="submit">Add Ticket</button>
        </form>
      )}

      {/* ---------------- TOOLS (FILE UPLOAD) ---------------- */}
      {tab === "tools" && (
        <form onSubmit={submitBill}>
          <h3>Upload Bill (PDF / Image)</h3>

          <input
            type="file"
            accept="application/pdf,image/*"
            onChange={(e) => setBillForm({ ...billForm, file: e.target.files[0] })}
            required
          />

          <input
            placeholder="Month (YYYY-MM)"
            value={billForm.month_year}
            onChange={(e) => setBillForm({ ...billForm, month_year: e.target.value })}
          />

          <button type="submit">Upload Bill</button>
        </form>
      )}

      {/* ---------------- HISTORY ---------------- */}
      {tab === "history" && (
        <div>
          <h3>History</h3>

          <div style={{ display: "flex", gap: 20 }}>
            <div>
              <h4>Travel</h4>
              {history.travel.map((t) => (
                <div key={t.id}>
                  {t.travel_date} — {t.location_from} → {t.location_to} — ₹{t.amount}
                </div>
              ))}
            </div>

            <div>
              <h4>Ticket</h4>
              {history.ticket.map((t) => (
                <div key={t.id}>
                  {t.ticket_date} — {t.purpose} — ₹{t.amount}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ---------------- GRAPH (Chart.js) ---------------- */}
      {tab === "graph" && (
        <div>
          <h3>Monthly Graph</h3>

          {graph.length === 0 && <p>No data</p>}

          {graph.length > 0 && (
            <>
              <Bar
                data={{
                  labels: graph.map((g) => g.month_year),
                  datasets: [
                    {
                      label: "Travel Expense",
                      data: graph.map((g) => g.total_travel),
                      backgroundColor: "rgba(75, 192, 192, 0.6)",
                    },
                    {
                      label: "Ticket Expense",
                      data: graph.map((g) => g.total_ticket),
                      backgroundColor: "rgba(255, 159, 64, 0.6)",
                    },
                  ],
                }}
              />

              <Line
                data={{
                  labels: graph.map((g) => g.month_year),
                  datasets: [
                    {
                      label: "Travel Trend",
                      data: graph.map((g) => g.total_travel),
                      borderColor: "blue",
                      fill: false,
                    },
                    {
                      label: "Ticket Trend",
                      data: graph.map((g) => g.total_ticket),
                      borderColor: "red",
                      fill: false,
                    },
                  ],
                }}
              />
            </>
          )}
        </div>
      )}
    </div>
  );
}
